const raw = $input.first().json;
const d = raw.body || raw.query || raw;
d.runtime_mode = d.runtime_mode || "MOCK";
d.correlation_id = d.correlation_id || ("PROD-" + Date.now());
d.request_id = d.request_id || ("REQ-" + Math.random().toString(36).substr(2,8).toUpperCase());
d.user = d.user || {id:"system",name:"Auto",role:"agent",department:"producao"};
d.payload = d.payload || {};
d.metadata = d.metadata || {};
const pl = d.payload;
const msg = (d.message || "").toLowerCase();
const et = (pl.event_type || "").toLowerCase();
if (!d.action) {
  if (et === "daily_report") d.action = "daily_report";
  else if (et === "material_missing" || /falta material|sem chapa|precisa comprar|material pendente/.test(msg)) d.action = "detect_missing_material";
  else if (et === "deadline_changed" || /atrasad|prazo|deadline/.test(msg)) d.action = "detect_delay";
  else if (et === "card_moved" || et === "op_created" || /kanban|card|\bop\b|producao/.test(msg)) d.action = "analyze_op";
  else d.action = "event_intake";
}
return [{json: d}];

const d = $input.first().json;
const pl = d.payload || {};
const action = d.action || "event_intake";
const msg = d.message || "";
if (action === "daily_report") { d._validation = {valid:true,missing:[]}; d._needs_info = false; return [{json:d}]; }
const missing = [];
const hasId = pl.op_id || pl.card_id;
const hasMsg = msg.length > 5;
const hasMats = (pl.materials || []).length > 0;
if (action === "detect_missing_material" && !hasMats && !/falta|material|chapa|comprar/.test(msg.toLowerCase())) missing.push("materials");
if (!hasId && !hasMsg) missing.push("op_id_or_card_id_or_message");
d._validation = {valid: missing.length === 0, missing};
d._needs_info = missing.length > 0;
return [{json: d}];

const d = $input.first().json;
d._status = "needs_info";
const miss = (d._validation ? d._validation.missing : null) || [];
d._clarification = {questions: miss.map(function(m){return "Informar " + m + " para continuar";}), missing: miss};
return [{json: d}];

const d = $input.first().json;
const pl = d.payload || {};
const now = new Date();
const opId = pl.op_id || ("OP-MOCK-" + Math.random().toString(36).substr(2,6).toUpperCase());
const cardId = pl.card_id || ("CARD-MOCK-" + Math.random().toString(36).substr(2,6).toUpperCase());
const deadlineStr = pl.deadline || "";
const deadline = deadlineStr ? new Date(deadlineStr) : new Date(now.getTime() + 3 * 86400000);
const daysUntil = Math.round((deadline - now) / 86400000);
const chk = pl.checklist && pl.checklist.length > 0 ? pl.checklist : [{item:"Montagem",done:true},{item:"Teste",done:false},{item:"Pintura",done:false}];
const tot = chk.length;
const done = chk.filter(function(i){return i.done;}).length;
const pct = Math.round((done / tot) * 100);
if (d.runtime_mode === "PORTAL") {
  d._op_context = {note:"TODO: GET /api/producao/ops/" + (pl.op_id||"") + " e GET /api/kanban/cards/" + (pl.card_id||""), op_id:pl.op_id, card_id:pl.card_id};
} else {
  d._op_context = {
    op_id: opId, card_id: cardId,
    title: pl.title || ("OP " + opId + " - Producao"),
    status: pl.status || "in_progress",
    column: pl.column || "Em Producao",
    responsible: pl.responsible || "",
    deadline: deadline.toISOString().split("T")[0],
    days_until_deadline: daysUntil,
    is_overdue: daysUntil < 0,
    checklist: chk, checklist_total: tot, checklist_done: done, checklist_percent: pct,
    materials: pl.materials || [],
    board_type: pl.board_type || "producao",
    customer_impact_possible: /urgente|cliente|entrega|prazo/.test((pl.description || d.message || "").toLowerCase())
  };
}
return [{json: d}];

const d = $input.first().json;
const ctx = d._op_context || {};
const pl = d.payload || {};
const msg = (d.message || "").toLowerCase();
const mats = ctx.materials || pl.materials || [];
const hasMissingMat = mats.some(function(m){ return ["missing","pending","out_of_stock","faltando"].includes((m.status||"").toLowerCase()); }) ||
  /falta|sem chapa|precisa comprar|material pendente/.test(msg);
const hasNoResp = !ctx.responsible || ctx.responsible === "";
const hasNoDeadline = !pl.deadline && ctx.days_until_deadline === undefined;
const isBlocked = (pl.status||"").toLowerCase().includes("block") || /bloqueado|blocked/.test(msg);
const daysInCol = ((pl.metadata || {}).days_in_column) || 0;
d._analysis = {
  op_id: ctx.op_id, card_id: ctx.card_id, title: ctx.title, status: ctx.status,
  responsible: ctx.responsible, deadline: ctx.deadline,
  days_until_deadline: ctx.days_until_deadline,
  checklist_percent: ctx.checklist_percent || 0,
  is_overdue: ctx.is_overdue === true,
  is_blocked: isBlocked,
  has_missing_material: hasMissingMat,
  has_no_responsible: hasNoResp,
  has_no_deadline: hasNoDeadline,
  has_pending_checklist: (ctx.checklist_percent || 0) < 100,
  customer_impact_possible: ctx.customer_impact_possible || false,
  stalled_in_column: daysInCol > 3,
  summary: "OP " + (ctx.op_id||"") + " | status=" + (ctx.status||"") +
    " | checklist=" + (ctx.checklist_percent||0) + "%" +
    " | prazo=" + (ctx.is_overdue ? "ATRASADO" : (ctx.days_until_deadline + " dias")) +
    " | material=" + (hasMissingMat ? "FALTANDO" : "OK") +
    " | resp=" + (hasNoResp ? "NAO DEFINIDO" : (ctx.responsible||"OK"))
};
return [{json: d}];

const d = $input.first().json;
const a = d._analysis || {};
const msg = (d.message || "").toLowerCase();
const pl = d.payload || {};
const descLower = ((pl.title || "") + " " + (pl.description || "")).toLowerCase();
const isEX = /\bex\b|area classificada|inmetro|explosao|explosivo/.test(msg) || /\bex\b|area classificada|inmetro/.test(descLower);
let risk = "low";
if (isEX) {
  risk = "critical";
} else if (a.is_overdue || a.has_missing_material) {
  risk = "high";
} else if (a.has_no_responsible || a.has_no_deadline || a.stalled_in_column || a.is_blocked) {
  risk = "medium";
} else if ((a.days_until_deadline !== undefined && a.days_until_deadline <= 1 && a.checklist_percent < 80)) {
  risk = "medium";
} else if (a.has_pending_checklist || a.customer_impact_possible) {
  risk = "medium";
}
d._risk_level = risk;
d._requires_approval = isEX || (d.action === "move_card_request" && ["medium","high","critical"].includes(risk));
d._policy = {
  comment_allowed: true, alert_allowed: true, compras_request_allowed: true,
  auto_move_allowed: pl.auto_move_allowed === true && pl.approved === true,
  finalize_op_blocked: true,
  change_deadline_requires_approval: true,
  is_ex_area: isEX
};
return [{json: d}];

const d = $input.first().json;
const pl = d.payload || {};
const ops = pl.ops || [
  {op_id:"OP-001",status:"in_progress",responsible:"Carlos",days_until_deadline:2,checklist_percent:60,has_missing_material:false},
  {op_id:"OP-002",status:"in_progress",responsible:"",days_until_deadline:-1,checklist_percent:40,has_missing_material:true},
  {op_id:"OP-003",status:"done",responsible:"Ana",days_until_deadline:5,checklist_percent:100,has_missing_material:false},
  {op_id:"OP-004",status:"in_progress",responsible:"Bruno",days_until_deadline:0,checklist_percent:30,has_missing_material:false}
];
const atrasadas = ops.filter(function(o){return o.days_until_deadline < 0 && o.status !== "done";});
const semResp = ops.filter(function(o){return !o.responsible || o.responsible === "";});
const comMat = ops.filter(function(o){return o.has_missing_material;});
const prazoHj = ops.filter(function(o){return o.days_until_deadline === 0 && o.status !== "done";});
d._daily_report = {
  total_ops: ops.length, ops_atrasadas: atrasadas.length,
  ops_sem_responsavel: semResp.length, ops_material_pendente: comMat.length,
  ops_prazo_hoje: prazoHj.length,
  atrasadas: atrasadas.map(function(o){return o.op_id;}),
  sem_responsavel: semResp.map(function(o){return o.op_id;}),
  material_pendente: comMat.map(function(o){return o.op_id;}),
  acoes_recomendadas: [
    atrasadas.length > 0 ? "Verificar OPs atrasadas: " + atrasadas.map(function(o){return o.op_id;}).join(", ") : null,
    semResp.length > 0 ? "Definir responsavel para: " + semResp.map(function(o){return o.op_id;}).join(", ") : null,
    comMat.length > 0 ? "Acionar compras para: " + comMat.map(function(o){return o.op_id;}).join(", ") : null
  ].filter(function(x){return x !== null;}),
  generated_at: new Date().toISOString(),
  note: d.runtime_mode === "PORTAL" ? "TODO: GET /api/producao/ops?status=active" : "MOCK: daily_report simulado"
};
d._status = "daily_report_ready";
return [{json: d}];

const d = $input.first().json;
const pl = d.payload || {};
const policy = d._policy || {};
if (policy.auto_move_allowed && pl.approved === true) {
  d._move_result = {
    action: "move_card_placeholder",
    card_id: pl.card_id,
    target_column: (pl.metadata && pl.metadata.target_column) ? pl.metadata.target_column : "Proximo_Estagio",
    note: d.runtime_mode === "PORTAL" ? "TODO: POST /api/kanban/cards/{id}/move" : "MOCK: move placeholder - nao mover real"
  };
  d._status = "move_card_placeholder";
} else {
  d._requires_approval = true;
  d._approval_id = "appr_prod_" + Math.random().toString(36).substr(2,8);
  d._status = "approval_pending";
  d._blocked_reason = "Mover card requer aprovacao ou auto_move_allowed=true + approved=true";
}
return [{json: d}];

const d = $input.first().json;
const a = d._analysis || {};
const pl = d.payload || {};
const msg = (d.message || "").toLowerCase();
const mats = (pl.materials || []).filter(function(m){ return ["missing","pending","out_of_stock","faltando"].includes((m.status||"").toLowerCase()); });
const hasMissingMat = a.has_missing_material || false;
// Alerts
const alerts = [];
if (a.is_overdue) alerts.push({alert_type:"delay",severity:"high",title:"OP Atrasada",message:"OP " + (a.op_id||"") + " atrasada. Prazo: " + (a.deadline||""),responsible:a.responsible,op_id:a.op_id,card_id:a.card_id});
if (hasMissingMat) alerts.push({alert_type:"missing_material",severity:"high",title:"Material Faltando",message:"Material pendente para OP " + (a.op_id||""),responsible:a.responsible,op_id:a.op_id,card_id:a.card_id});
if (a.has_no_responsible) alerts.push({alert_type:"no_responsible",severity:"medium",title:"Sem Responsavel",message:"OP " + (a.op_id||"") + " sem responsavel",op_id:a.op_id,card_id:a.card_id});
if (a.has_no_deadline) alerts.push({alert_type:"no_deadline",severity:"medium",title:"Sem Prazo",message:"OP " + (a.op_id||"") + " sem prazo",op_id:a.op_id,card_id:a.card_id});
if (d._risk_level === "critical") alerts.push({alert_type:"critical_compliance",severity:"critical",title:"Alerta Critico EX/INMETRO",message:"EX/INMETRO detectado. Revisao obrigatoria.",op_id:a.op_id,card_id:a.card_id});
d._alerts = alerts;
d._alert_result = {alert_count: alerts.length, alert_id: "alert_mock_" + Math.random().toString(36).substr(2,8), note: d.runtime_mode === "PORTAL" ? "TODO: POST /api/producao/ops/{id}/alerts" : "MOCK: " + alerts.length + " alertas"};
// Kanban Comment
const lines = ["Analise [" + d.correlation_id + "]"];
lines.push(a.summary || "Analise realizada");
if (alerts.length > 0) lines.push("Alertas: " + alerts.map(function(al){return al.alert_type+"("+al.severity+")";}).join(", "));
if (hasMissingMat) lines.push("Material faltando - requisicao de compra preparada.");
if (a.is_overdue) lines.push("ATENCAO: OP atrasada.");
if (d._risk_level === "critical") lines.push("CRITICO: Revisao obrigatoria.");
d._kanban_comment = {comment_text: lines.join(" | "), card_id: a.card_id, prepared_by: "PRODUCAO Agent", prepared_at: new Date().toISOString(), note: d.runtime_mode === "PORTAL" ? "TODO: POST /api/kanban/cards/{id}/comments" : "MOCK: comment_prepared=true"};
// Compras Integration
if (hasMissingMat) {
  const matDesc = mats.length > 0 ? mats.map(function(m){return m.description||m.name||"material";}).join(", ") : (d.message || "material para OP");
  d._compras_payload = {
    runtime_mode: d.runtime_mode, correlation_id: d.correlation_id, request_id: d.request_id,
    source: "producao", user: d.user,
    message: "Comprar/cotar material para OP " + (a.op_id || pl.op_id || ""),
    action: "intake",
    payload: {
      op_id: a.op_id || pl.op_id || "",
      item_description: matDesc,
      quantity: mats.length > 0 ? (mats[0].quantity || "1") : "1",
      unit: mats.length > 0 ? (mats[0].unit || "un") : "un",
      deadline: a.deadline || pl.deadline || "",
      approved: false,
      customer: {company_name: "Producao Interna", email: "producao@vesper.com.br"}
    }
  };
  d._compras_result = {triggered: true, workflow_id: "k2Ss9Ct4aHKf67cf", note: d.runtime_mode === "PORTAL" ? "TODO: Execute Workflow k2Ss9Ct4aHKf67cf" : "MOCK: compras_triggered=true"};
  d._status = "compras_triggered";
} else {
  d._status = alerts.length > 0 ? "alert_created" : "analyzed";
}
return [{json: d}];

const d = $input.first().json;
const evtMap = {
  "event_intake": "producao.event_received",
  "analyze_op": "producao.op_analyzed",
  "detect_delay": "producao.delay_detected",
